// MsgServer is the server API for Msg service.
type MsgServer interface {
	// UpdateParams defines a (governance) operation for updating the module
	// parameters. The authority defaults to the x/gov module account.
	UpdateParams(context.Context, *MsgUpdateParams) (*MsgUpdateParamsResponse, error)
	// MsgRegisterProvider allows a Storage Provider to register themselves with the network.
	RegisterProvider(context.Context, *MsgRegisterProvider) (*MsgRegisterProviderResponse, error)
	// MsgAddProviderBond allows a provider or paired operator to top up provider bond.
	AddProviderBond(context.Context, *MsgAddProviderBond) (*MsgAddProviderBondResponse, error)
	// MsgWithdrawProviderBond allows a provider or paired operator to withdraw
	// excess provider bond while retaining policy-required liability backing.
	WithdrawProviderBond(context.Context, *MsgWithdrawProviderBond) (*MsgWithdrawProviderBondResponse, error)
	// MsgClaimProviderBondWithdrawal releases a mature delayed provider-bond
	// withdrawal from the provider-bond module account to its recorded recipient.
	ClaimProviderBondWithdrawal(context.Context, *MsgClaimProviderBondWithdrawal) (*MsgClaimProviderBondWithdrawalResponse, error)
	// MsgBindProviderStake records an observed provider/delegator/validator
	// binding. It does not make delegated stake assignment collateral yet.
	BindProviderStake(context.Context, *MsgBindProviderStake) (*MsgBindProviderStakeResponse, error)
	// MsgUnbindProviderStake removes an observed provider staking binding.
	UnbindProviderStake(context.Context, *MsgUnbindProviderStake) (*MsgUnbindProviderStakeResponse, error)
	// MsgSetProviderDraining allows a provider to opt out of new assignments.
	SetProviderDraining(context.Context, *MsgSetProviderDraining) (*MsgSetProviderDrainingResponse, error)
	// MsgUpdateProviderEndpoints allows a provider to update its registered endpoints.
	UpdateProviderEndpoints(context.Context, *MsgUpdateProviderEndpoints) (*MsgUpdateProviderEndpointsResponse, error)
	// MsgRequestProviderLink allows a provider key to request linking to an operator wallet.
	RequestProviderLink(context.Context, *MsgRequestProviderLink) (*MsgRequestProviderLinkResponse, error)
	// MsgApproveProviderLink allows an operator wallet to approve a pending provider link request.
	ApproveProviderLink(context.Context, *MsgApproveProviderLink) (*MsgApproveProviderLinkResponse, error)
	// MsgCancelProviderLink allows a provider key to cancel its pending provider link request.
	CancelProviderLink(context.Context, *MsgCancelProviderLink) (*MsgCancelProviderLinkResponse, error)
	// MsgUnpairProvider removes an existing provider<->operator link.
	UnpairProvider(context.Context, *MsgUnpairProvider) (*MsgUnpairProviderResponse, error)
	// MsgCreateDeal allows a user to create a new storage deal.
	CreateDeal(context.Context, *MsgCreateDeal) (*MsgCreateDealResponse, error)
	// MsgUpdateDealContent allows a user to commit or update the content (manifest) of a deal.
	UpdateDealContent(context.Context, *MsgUpdateDealContent) (*MsgUpdateDealContentResponse, error)
	// MsgBumpDealSetupSlot allows a deal owner to replace a single Mode 2 slot
	// during setup, before the first content commit.
	BumpDealSetupSlot(context.Context, *MsgBumpDealSetupSlot) (*MsgBumpDealSetupSlotResponse, error)
	// MsgCreateDealFromEvm allows a user to create a new storage deal
	// using an EVM-signed intent bridged into polystorechaind.
	CreateDealFromEvm(context.Context, *MsgCreateDealFromEvm) (*MsgCreateDealFromEvmResponse, error)
	// MsgUpdateDealContentFromEvm allows a user to update deal content
	// using an EVM-signed intent.
	UpdateDealContentFromEvm(context.Context, *MsgUpdateDealContentFromEvm) (*MsgUpdateDealContentFromEvmResponse, error)
	// MsgOpenRetrievalSession opens an on-chain retrieval session for a contiguous blob-range.
	OpenRetrievalSession(context.Context, *MsgOpenRetrievalSession) (*MsgOpenRetrievalSessionResponse, error)
	// MsgOpenRetrievalSessionSponsored opens a USER retrieval session funded by the requester
	// (not by the deal escrow). This is used for public/allowlisted/voucher retrievals.
	OpenRetrievalSessionSponsored(context.Context, *MsgOpenRetrievalSessionSponsored) (*MsgOpenRetrievalSessionSponsoredResponse, error)
	// MsgOpenProtocolRetrievalSession opens a protocol-funded retrieval session for audit/repair.
	OpenProtocolRetrievalSession(context.Context, *MsgOpenProtocolRetrievalSession) (*MsgOpenProtocolRetrievalSessionResponse, error)
	// MsgConfirmRetrievalSession confirms completion of a retrieval session (proof-of-validation).
	ConfirmRetrievalSession(context.Context, *MsgConfirmRetrievalSession) (*MsgConfirmRetrievalSessionResponse, error)
	// MsgCancelRetrievalSession cancels an expired retrieval session and unlocks fees.
	CancelRetrievalSession(context.Context, *MsgCancelRetrievalSession) (*MsgCancelRetrievalSessionResponse, error)
	// MsgSubmitRetrievalSessionProof submits proof-of-retrieval for a session (provider action).
	SubmitRetrievalSessionProof(context.Context, *MsgSubmitRetrievalSessionProof) (*MsgSubmitRetrievalSessionProofResponse, error)
	// MsgProveLiveness allows a Storage Provider to submit a proof of data liveness.
	ProveLiveness(context.Context, *MsgProveLiveness) (*MsgProveLivenessResponse, error)
	// MsgSignalSaturation allows a Storage Provider to signal high load for a deal.
	SignalSaturation(context.Context, *MsgSignalSaturation) (*MsgSignalSaturationResponse, error)
	// MsgStartSlotRepair marks a Mode 2 slot as repairing and sets a replacement candidate.
	StartSlotRepair(context.Context, *MsgStartSlotRepair) (*MsgStartSlotRepairResponse, error)
	// MsgCompleteSlotRepair promotes the pending replacement candidate to active.
	CompleteSlotRepair(context.Context, *MsgCompleteSlotRepair) (*MsgCompleteSlotRepairResponse, error)
	// MsgAddCredit allows a user to top up the escrow balance for a deal.
	AddCredit(context.Context, *MsgAddCredit) (*MsgAddCreditResponse, error)
	// MsgExtendDeal extends a deal term by paying spot storage price for existing bytes.
	ExtendDeal(context.Context, *MsgExtendDeal) (*MsgExtendDealResponse, error)
	// MsgUpdateDealRetrievalPolicy updates the on-chain retrieval policy for a deal.
	UpdateDealRetrievalPolicy(context.Context, *MsgUpdateDealRetrievalPolicy) (*MsgUpdateDealRetrievalPolicyResponse, error)
	// MsgWithdrawRewards allows a Storage Provider to withdraw accumulated rewards.
	WithdrawRewards(context.Context, *MsgWithdrawRewards) (*MsgWithdrawRewardsResponse, error)
}

